    tmp138 = einsum(tmp10, (0, 1, 2), tmp3, (3, 4, 2), (0, 1, 3, 4))
    del tmp3
    t2new.abab += einsum(tmp138, (0, 1, 2, 3), tmp103, (1, 3, 4, 5), (0, 2, 4, 5))
    del tmp103, tmp138
    tmp139 = einsum(tmp10, (0, 1, 2), tmp27, (3, 4, 2), (0, 1, 3, 4))
    del tmp10, tmp27
    t2new.abab += einsum(t1.aa, (0, 1), tmp139, (2, 0, 3, 4), (2, 3, 1, 4)) * -1
    del tmp139

    return {"t1new": t1new, "t2new": t2new}

